@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" SearchTextChanged="@(v => searchText = v)" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var index = i;
            <KanbanColumn ColumnName="@columns[index]"
                          ColumnIndex="index"
                          Tasks="@GetFilteredTasks(columns[index])"
                          OnMoveTask="HandleMoveTask"
                          OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            loading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var query = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    private async Task HandleMoveTask((int TaskId, int TargetColumnIndex) args)
    {
        var newStatus = columns[args.TargetColumnIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, newStatus);
            var task = allTasks.First(t => t.Id == args.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // The service may not set Status to the column's status, so ensure it matches
            if (newTask.Status != args.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
                newTask = newTask with { Status = args.Status };
            }
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

